import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();

  const initialFormState = {
    // Thông tin cơ sở chung
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    ngayThanhLap: '', giayPhepKinhDoanh: '', loaiCoSoDangKy: '', trangThai: 'Đang hoạt động', ghiChu: '',
    
    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    
    // Dành cho Cơ sở gây nuôi (Thực vật)
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '',
    
    // Dành cho Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '',
    
    // Dành cho Cơ sở nuôi, động vật (MỚI)
    tenLoaiDongVat: '', soLuongDuc: 0, soLuongCai: 0, nguonGocGiong: '', maSoGiayPhepNuoi: '',

    // Thông tin sản phẩm/loài nuôi ban đầu (sẽ được gom vào mảng products)
    tenLamSan: '', tenKhoaHoc: '', khoiLuong: '', tongDan: '',
    loaiHinhCheBienGo: '', nguonGocGo: '',

    // Giấy phép
    issueDate: '', expiryDate: '',
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        if (jwtDecode(token).role === 'admin') setIsAdmin(true);
      } catch (err) {
        localStorage.removeItem('token');
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormState);
    setMessage({ type: '', text: '' });
  }, [initialFormState]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage({ type: '', text: '' });
    const token = localStorage.getItem('token');
    if (!token) {
      setMessage({ type: 'error', text: 'Bạn chưa đăng nhập.' });
      setLoading(false);
      return;
    }

    try {
        const submissionData = { ...formData };
        submissionData.products = [];

        // Logic gom dữ liệu vào mảng products cho từng loại cơ sở
        if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && submissionData.tenLamSan) {
            submissionData.products.push({
                tenLamSan: submissionData.tenLamSan,
                tenKhoaHoc: speciesOptions.find(s => s.name === submissionData.tenLamSan)?.scientificName || '',
                khoiLuong: submissionData.tongDan,
                donViTinh: 'cá thể',
                mucDichNuoi: submissionData.mucDichNuoi,
                hinhThucNuoi: submissionData.hinhThucNuoi,
                maSoCoSoGayNuoi: submissionData.maSoCoSoGayNuoi
            });
        } else if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && submissionData.tenLamSan) {
            submissionData.products.push({
                tenLamSan: submissionData.tenLamSan,
                tenKhoaHoc: submissionData.tenKhoaHoc,
                khoiLuong: submissionData.khoiLuong,
                donViTinh: 'm³',
                loaiHinhCheBienGo: submissionData.loaiHinhCheBienGo,
                nguonGocGo: submissionData.nguonGocGo
            });
        } else if (submissionData.loaiCoSoDangKy === 'Đăng ký cơ sở nuôi, động vật' && submissionData.tenLoaiDongVat) {
             submissionData.products.push({
                tenLamSan: submissionData.tenLoaiDongVat, // Dùng chung trường tenLamSan
                khoiLuong: (parseInt(submissionData.soLuongDuc) || 0) + (parseInt(submissionData.soLuongCai) || 0),
                donViTinh: 'cá thể',
                soLuongDuc: submissionData.soLuongDuc,
                soLuongCai: submissionData.soLuongCai,
                nguonGocGiong: submissionData.nguonGocGiong,
                maSoGiayPhepNuoi: submissionData.maSoGiayPhepNuoi,
            });
        }
        
        // Xóa các trường đã được gom vào mảng products khỏi cấp cao nhất
        const fieldsToDelete = ['tenLamSan', 'tenKhoaHoc', 'khoiLuong', 'tongDan', 'loaiHinhCheBienGo', 'nguonGocGo', 'tenLoaiDongVat', 'soLuongDuc', 'soLuongCai', 'nguonGocGiong', 'maSoGiayPhepNuoi'];
        fieldsToDelete.forEach(field => delete submissionData[field]);

        await axios.post('http://localhost:10000/api/farms', submissionData, {
            headers: { Authorization: `Bearer ${token}` }
        });
        setMessage({ type: 'success', text: 'Đăng ký cơ sở thành công!' });
        resetForm();
    } catch (err) {
        const errorMessage = err.response?.data?.message || 'Đăng ký cơ sở thất bại.';
        setMessage({ type: 'error', text: errorMessage });
    } finally {
        setLoading(false);
    }
  };
  
  // Hàm handleFileUpload và handleBulkSubmit giữ nguyên logic cập nhật lần trước
  // ...

  return (
    <div className="khai-bao-container">
      <h2>Đăng ký cơ sở</h2>
      {message.type && (
        <div className={`message ${message.type}`}>
          {message.text}
          <button onClick={() => setMessage({ type: '', text: '' })} className="close-message-button">x</button>
        </div>
      )}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          {/* Các trường thông tin cơ sở và người đại diện không đổi */}
          {/* ... */}
        </section>
        
        <section className="khai-bao-section">
          <h3>Loại cơ sở đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
            <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi (Thực vật)</option>
              <option value="Đăng ký cơ sở nuôi, động vật">Cơ sở nuôi, động vật</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>
        </section>

        {/* Khối cho Cơ sở gây nuôi (Thực vật) */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Thông tin cơ sở gây nuôi</h3>
            <div className="form-group"><label>Mục đích nuôi:</label><input type="text" name="mucDichNuoi" value={formData.mucDichNuoi} onChange={handleChange} /></div>
            <div className="form-group"><label>Hình thức nuôi:</label><input type="text" name="hinhThucNuoi" value={formData.hinhThucNuoi} onChange={handleChange} /></div>
            <div className="form-group"><label>Mã số CS gây nuôi:</label><input type="text" name="maSoCoSoGayNuoi" value={formData.maSoCoSoGayNuoi} onChange={handleChange} /></div>
            <div className="form-group"><label>Tổng đàn:</label><input type="number" name="tongDan" value={formData.tongDan} onChange={handleChange} /></div>
            <div className="form-group"><label>Loài nuôi:</label><select name="tenLamSan" value={formData.tenLamSan} onChange={handleChange}><option value="">-- Chọn loài --</option>{speciesOptions.map(s => <option key={s.name} value={s.name}>{s.name}</option>)}</select></div>
          </section>
        )}

        {/* Khối MỚI cho Cơ sở nuôi, động vật */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở nuôi, động vật' && (
            <section className="khai-bao-section">
                <h3>Thông tin cơ sở nuôi, động vật</h3>
                <div className="form-group"><label>Tên loài động vật:</label><input type="text" name="tenLoaiDongVat" value={formData.tenLoaiDongVat} onChange={handleChange} /></div>
                <div className="form-group"><label>Số lượng con đực:</label><input type="number" name="soLuongDuc" value={formData.soLuongDuc} onChange={handleChange} /></div>
                <div className="form-group"><label>Số lượng con cái:</label><input type="number" name="soLuongCai" value={formData.soLuongCai} onChange={handleChange} /></div>
                <div className="form-group"><label>Nguồn gốc giống:</label><input type="text" name="nguonGocGiong" value={formData.nguonGocGiong} onChange={handleChange} /></div>
                <div className="form-group"><label>Mã số giấy phép (CITES,...):</label><input type="text" name="maSoGiayPhepNuoi" value={formData.maSoGiayPhepNuoi} onChange={handleChange} /></div>
            </section>
        )}

        {/* Khối cho Cơ sở kinh doanh, chế biến gỗ */}
        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
            <section className="khai-bao-section">
                <h3>Thông tin cơ sở kinh doanh, chế biến gỗ</h3>
                <div className="form-group"><label>Tên lâm sản:</label><input type="text" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange} /></div>
                <div className="form-group"><label>Khối lượng (m³):</label><input type="number" name="khoiLuong" value={formData.khoiLuong} onChange={handleChange} step="any" /></div>
                <div className="form-group"><label>Nguồn gốc gỗ:</label><select name="nguonGocGo" value={formData.nguonGocGo} onChange={handleChange}><option value="">-- Chọn --</option><option value="Nhập khẩu">Nhập khẩu</option><option value="Vườn">Vườn</option><option value="Khác">Khác</option></select></div>
            </section>
        )}

        <div className="form-actions">
          <button type="submit" className="submit-button" disabled={loading}>{loading ? 'Đang gửi...' : 'Đăng ký cơ sở'}</button>
          <button type="button" onClick={resetForm} className="reset-button" disabled={loading}>Đặt lại</button>
        </div>
      </form>

      {/* Phần tải lên hàng loạt giữ nguyên */}
      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          {/* ... */}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
